-- Luke Chapter 13
-- Theme: Repentance, the Kingdom's Growth, and the Narrowness of Salvation
-- 35 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 13,
  'Luke 13 opens with two unsolicited news items about recent tragedies — Galileans killed by Pilate at the altar and eighteen people crushed by the tower of Siloam — that the crowd had apparently linked to divine judgment on the victims. Jesus refuses this theodicy twice with identical language: "Think ye that these were sinners above all?" (vv.2,4). The real implication of both disasters is not that those particular people deserved death, but that all are equally guilty and equally liable to sudden perishing unless they repent. The double demand — "Except ye repent, ye shall all likewise perish" — establishes repentance as the chapter''s organizing imperative.' ||
  'The parable of the barren fig tree (vv.6-9) extends this call to repentance with a note of merciful delay: the owner wants to cut it down after three fruitless years, but the vinedresser intercedes for one more year of intensive cultivation. The fig tree is Israel; the three years are Jesus''s ministry; the intercession is his grace before judgment. The healing of the bent woman on the Sabbath (vv.10-17) is Luke''s last synagogue healing and the fifth Sabbath controversy in the Gospel. The woman''s condition — eighteen years bent double — echoes the eighteen killed at Siloam, and her release on the Sabbath is declared the proper Sabbath activity: setting free what Satan has bound.' ||
  'Two paired parables — the mustard seed and the leaven (vv.18-21) — address the apparent smallness of the kingdom movement: from an invisible seed comes a sheltering tree; from a pinch of leaven comes a leavened lump. Both parables address the disciples'' discouragement at the kingdom''s modest beginnings by promising organic, hidden growth toward ultimate manifestation. The question of the narrow door (vv.22-30) is the chapter''s eschatological climax: Jesus is on his way to Jerusalem (v.22), and a questioner asks if only a few will be saved.' ||
  'Jesus''s answer does not satisfy the questioner''s theoretical curiosity but issues a personal urgent call: "Strive to enter in at the strait gate." Many will seek to enter at the last moment and find the door shut. The Gentiles from east and west will recline at the patriarchal feast while those who assumed inclusion by ethnic right are excluded. The chapter closes with the Pharisees'' warning about Herod''s threat and Jesus''s lament over Jerusalem (vv.31-35): the city that kills prophets will see her house left desolate, and Jesus will not be seen again until they say "Blessed is he that cometh in the name of the Lord."',
  'Repentance, the Kingdom''s Growth, and the Narrowness of Salvation',
  'μετανοέω (metanoeō)',
  'metanoeō means to repent, to change one''s mind and direction completely, to turn from one orientation to another. It is derived from meta (after, change) + noeō (to think, perceive), thus literally "to think differently after." In Luke 13, Jesus issues the word''s imperative form twice in the same breath (vv.3,5: "except ye repent"), making repentance the urgent, non-negotiable response to mortality and the gracious delay of judgment. The word is not merely emotional remorse but a reorientation of the whole person toward God.',
  '["Two Tragedies and the Call to Universal Repentance (vv.1-5)","The Barren Fig Tree: Mercy Extended, Judgment Pending (vv.6-9)","The Bent Woman Healed: Sabbath as Liberation (vv.10-17)","Mustard Seed and Leaven: The Kingdom''s Hidden Growth (vv.18-21)","The Narrow Door and the Lament over Jerusalem (vv.22-35)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'There were present at that season some that told him of the Galilaeans, whose blood Pilate had mingled with their sacrifices.', 'Παρῆσαν δέ τινες ἐν αὐτῷ τῷ καιρῷ ἀπαγγέλλοντες αὐτῷ περὶ τῶν Γαλιλαίων, ὧν τὸ αἷμα Πιλᾶτος ἔμιξεν μετὰ τῶν θυσιῶν αὐτῶν.', 'Parēsan de tines en autō tō kairō apangellontes autō peri tōn Galilaiōn, hōn to haima Pilatos emiXen meta tōn thusiōn autōn.', 'This atrocity is not recorded elsewhere, but Pilate''s brutal suppression of Galilean pilgrims at the temple is historically plausible given his well-documented cruelty (cf. Josephus). "Mingled with their sacrifices" (emiXen meta tōn thusiōn autōn) — killed while performing temple worship, so their blood mixed with the sacrificial blood. The report was clearly meant as a test: how would Jesus interpret this? Was it divine judgment on the victims?', NULL),
  (2, 'And Jesus answering said unto them, Suppose ye that these Galilaeans were sinners above all the Galilaeans, because they suffered such things?', 'καὶ ἀποκριθεὶς εἶπεν αὐτοῖς, Δοκεῖτε ὅτι οἱ Γαλιλαῖοι οὗτοι ἁμαρτωλοὶ παρὰ πάντας τοὺς Γαλιλαίους ἐγένοντο, ὅτι τοιαῦτα πεπόνθασιν;', 'kai apokritheis eipen autois, Dokeite hoti hoi Galilaioi houtoi hamartōloi para pantas tous Galilaiaus egenonto, hoti toiauta peponThasin?', '"Suppose ye" (Dokeite — do you think, is it your assumption?) directly challenges the folk theology that identifies unusual suffering with unusual sin. "Sinners above all" (hamartōloi para pantas — sinners in comparison with all) — the comparative reveals the questioner''s implicit ranking system. Jesus refuses to grade sinners by their sufferings. The assumption that victims of tragedy deserve their fate more than survivors is both theologically false and morally dangerous.', NULL),
  (3, 'I tell you, Nay: but, except ye repent, ye shall all likewise perish.', 'οὐχί, λέγω ὑμῖν· ἀλλ'' ἐὰν μὴ μετανοῆτε, πάντες ὁμοίως ἀπολεῖσθε.', 'ouchi, legō humin; all'' ean mē metanoēte, pantes homoiōs apoleisthe.', '"Nay" (ouchi — emphatically no) — a direct negation of the theodicy. But the refutation is immediately turned into a warning: "except ye repent, ye shall all likewise perish." The word "likewise" (homoiōs) is crucial — not by Pilate''s sword or a falling tower necessarily, but perish you will, and just as suddenly and unexpectedly. The tragedies are mirrors showing every hearer their own mortality and need for repentance.', NULL),
  (4, 'Or those eighteen, upon whom the tower in Siloam fell, and slew them, think ye that they were sinners above all men that dwelt in Jerusalem?', 'ἢ ἐκεῖνοι οἱ δεκαοκτώ, ἐφ'' οὓς ἔπεσεν ὁ πύργος ἐν τῷ Σιλωάμ, καὶ ἀπέκτεινεν αὐτούς, δοκεῖτε ὅτι αὐτοὶ ὀφειλέται ἐγένοντο παρὰ πάντας ἀνθρώπους τοὺς κατοικοῦντας Ἰερουσαλήμ;', 'ē ekeinoi hoi dekaOktō, eph'' hous epesen ho purgos en tō Silōam, kai apektEinen autous, dokeite hoti autoi opheiletai egenonto para pantas anthrōpous tous katoikountas Ierousalēm?', 'Siloam was a pool near the south wall of Jerusalem (John 9:7). A tower collapse there — possibly during construction of Pilate''s aqueduct — killed eighteen. "Debtors" (opheiletai — those who owe, those obligated, sinners in the sense of being in debt to divine justice). Jesus uses the same logical structure as v.2: do you think they owed more than everyone else in Jerusalem? The rhetorical question expects the same negative answer.', NULL),
  (5, 'I tell you, Nay: but, except ye repent, ye shall all likewise perish.', 'οὐχί, λέγω ὑμῖν· ἀλλ'' ἐὰν μὴ μετανοῆτε, πάντες ὁμοίως ἀπολεῖσθε.', 'ouchi, legō humin; all'' ean mē metanoēte, pantes homoiōs apoleisthe.', 'The exact repetition of v.3 creates a refrain of urgency. Two different tragedies — one politically violent, one structurally catastrophic — both yield the identical lesson. The variety of the disasters (human cruelty, structural collapse) represents the range of ways death can come without warning. The twofold repetition of the summons to repentance functions liturgically, like a doubled "Selah" — pause, consider, this applies to you.', NULL),
  (6, 'He spake also this parable; A certain man had a fig tree planted in his vineyard; and he came and sought fruit thereon, and found none.', 'Ἔλεγεν δὲ ταύτην τὴν παραβολήν· Συκῆν εἶχέν τις πεφυτευμένην ἐν τῷ ἀμπελῶνι αὐτοῦ, καὶ ἦλθεν ζητῶν καρπὸν ἐν αὐτῇ, καὶ οὐχ εὗρεν.', 'Elegen de tautēn tēn parabolēn; Sukēn eichen tis pephuteumenēn en tō ampelōni autou, kai ēlthen zētōn karpon en autē, kai ouch heuREn.', 'The fig tree is a classic OT symbol for Israel (Hos 9:10; Mic 7:1; Jer 8:13). Planting a fig tree in a vineyard (ampelōni — associated with Israel in Isa 5:1-7) places both symbols together. The owner "came and sought fruit" (ēlthen zētōn karpon) — the Messiah''s coming to Israel seeking the fruit of covenant faithfulness, and finding none (ouch heuREn — not finding it). The parable immediately follows the double call to repentance.', NULL),
  (7, 'Then said he unto the dresser of his vineyard, Behold, these three years I come seeking fruit on this fig tree, and find none: cut it down; why cumbereth it the ground?', 'εἶπεν δὲ πρὸς τὸν ἀμπελουργόν, Ἰδοὺ τρία ἔτη ἀφ'' οὗ ἔρχομαι ζητῶν καρπὸν ἐν τῇ συκῇ ταύτῃ, καὶ οὐχ εὑρίσκω· ἔκκοψον αὐτήν· ἵνα τί καὶ τὴν γῆν καταργεῖ;', 'eipen de pros ton ampElourGon, Idou tria etē aph'' hou erchomai zētōn karpon en tē sukē tautē, kai ouch heuriskō; ekKopson autēn; hina ti kai tēn gēn katargei?', '"Three years" (tria etē) corresponds to Jesus''s approximately three-year ministry before his crucifixion — the period during which Israel was visited by its Messiah with unprecedented signs and proclamation. "Cut it down" (ekKopson autēn — chop it out) — the owner''s judgment is reasonable and just. "Why cumbereth it the ground?" (hina ti kai tēn gēn katargei — why does it also render the ground useless?) — a fruitless tree depletes the soil and prevents something productive from growing.', NULL),
  (8, 'And he answering said unto him, Lord, let it alone this year also, till I shall dig about it, and dung it:', 'ὁ δὲ ἀποκριθεὶς λέγει αὐτῷ, Κύριε, ἄφες αὐτὴν καὶ τοῦτο τὸ ἔτος, ἕως ὅτου σκάψω περὶ αὐτὴν καὶ βάλω κόπρια·', 'ho de apokritheis legei autō, Kurie, aphes autēn kai touto to etos, heōs hotou skapsō peri autēn kai balō kopria;', 'The vinedresser (ampelourGos — identified with Jesus as the intercessor) pleads for one more year. "Let it alone" (aphes autēn — leave it, forgive/spare it; the word used for forgiveness). "Dig about it" (skapsō — to dig, loosen the soil) and "dung it" (balō kopria — apply manure) represent the intensive, costly ministry of Jesus: teaching, healing, calling to repentance — every possible means of producing fruit before judgment falls.', NULL),
  (9, 'And if it bear fruit, well: and if not, then after that thou shalt cut it down.', 'κἂν μὲν ποιήσῃ καρπόν· εἰ δὲ μήγε, εἰς τὸ μέλλον ἐκκόψεις αὐτήν.', 'kan men poiēsē karpon; ei de mēge, eis to mellon ekkopseis autēn.', 'The conditional structure preserves both hope and warning. "If it bear fruit" (poiēsē karpon — should it produce fruit) — the outcome is uncertain and depends on the response to the year of intensive grace. "Well" (implied — a suppressed apodosis, too obvious to state). "If not" (ei de mēge) — the judgment is deferred but not canceled; "thou shalt cut it down" (ekkopseis autēn) remains as the certain eventual outcome of persistent fruitlessness.', NULL),
  (10, 'And he was teaching in one of the synagogues on the sabbath.', 'Ἦν δὲ διδάσκων ἐν μιᾷ τῶν συναγωγῶν ἐν τοῖς σάββασιν.', 'Ēn de didaskōn en mia tōn sunagōgōn en tois sabbasin.', 'The setting shifts to a synagogue on the Sabbath — the fifth and final Sabbath controversy in Luke''s Gospel (cf. 4:31; 6:1-5; 6:6-11; 14:1-6). The regular teaching role (ēn didaskōn — was teaching, imperfect: ongoing practice) establishes Jesus''s authority in the synagogue setting, making the subsequent confrontation all the more pointed. The Sabbath day becomes the occasion for demonstrating what the Sabbath is truly for.', NULL),
  (11, 'And, behold, there was a woman which had a spirit of infirmity eighteen years, and was bowed together, and could in no wise lift up herself.', 'καὶ ἰδοὺ γυνὴ ἦν πνεῦμα ἔχουσα ἀσθενείας ἔτη δεκαοκτώ, καὶ ἦν συγκύπτουσα καὶ μὴ δυναμένη ἀνακύψαι εἰς τὸ παντελές.', 'kai idou gunē ēn pneuma echousa astheEnias etē dekaOktō, kai ēn sungkuptousa kai mē dunamenē anakupsai eis to panteles.', '"Behold" (idou — see! a narrative attention-marker) introduces a woman who has suffered eighteen years — the same number as those killed at Siloam (v.4), perhaps intentionally linking her suffering to the chapter''s meditation on mortality and grace. "Bowed together" (sungkuptousa — bent completely forward, unable to stand erect) and "could in no wise lift up herself" (eis to panteles — to any extent whatsoever, in any degree) describes total, chronic incapacity. A spirit of infirmity (v.16 identifies it as satanic bondage) has imposed this condition.', NULL),
  (12, 'And when Jesus saw her, he called her to him, and said unto her, Woman, thou art loosed from thine infirmity.', 'ἰδὼν δὲ αὐτὴν ὁ Ἰησοῦς προσεφώνησεν καὶ εἶπεν αὐτῇ, Γύναι, ἀπολέλυσαι τῆς ἀσθενείας σου·', 'idōn de autēn ho Iēsous prosephōnēsen kai eipen autē, Gunai, apolelUsai tēs astheEnias sou;', '"When Jesus saw her" — he took the initiative; no request was made. "Called her" (prosephōnēsen — called to her, summoned her forward) — a public, visible act in the synagogue setting. "Thou art loosed" (apolelUsai — perfect passive: you have been released, the release stands) — the divine pronouncement precedes the physical restoration. The word is the same used for releasing prisoners or debts (aphiēmi family); Jesus declares her release from an eighteen-year captivity.', NULL),
  (13, 'And he laid his hands on her: and immediately she was made straight, and glorified God.', 'καὶ ἐπέθηκεν αὐτῇ τὰς χεῖρας· καὶ παραχρῆμα ἀνωρθώθη, καὶ ἐδόξαζεν τὸν Θεόν.', 'kai epethēken autē tas cheiras; kai parachrēma anōrthōthē, kai edoxazen ton Theon.', '"Laid his hands on her" — the physical touch of the healing. "Immediately" (parachrēma — instantly, at that very moment) — eighteen years undone in a moment. "Was made straight" (anōrthōthē — aorist passive: was straightened up, erected upright) — the passive indicates divine action. "Glorified God" (edoxazen ton Theon — imperfect: kept giving glory to God) — the immediate, spontaneous, and continuous response of the healed. The Sabbath healing produces praise, not controversy — from the woman''s perspective.', NULL),
  (14, 'And the ruler of the synagogue answered with indignation, because that Jesus had healed on the sabbath day, and said unto the people, There are six days in which men ought to work: in them therefore come and be healed, and not on the sabbath day.', 'ἀποκριθεὶς δὲ ὁ ἀρχισυνάγωγος, ἀγανακτῶν ὅτι τῷ σαββάτῳ ἐθεράπευσεν ὁ Ἰησοῦς, ἔλεγεν τῷ ὄχλῳ ὅτι Ἓξ ἡμέραι εἰσὶν ἐν αἷς δεῖ ἐργάζεσθαι· ἐν αὐταῖς οὖν ἐρχόμενοι θεραπεύεσθε, καὶ μὴ τῇ ἡμέρᾳ τοῦ σαββάτου.', 'apokritheis de ho archisunagōgos, aganaktōn hoti tō sabbatō etherapeuse ho Iēsous, elegen tō ochlō hoti Hex hēmerai eisin en hais dei ergazesthai; en autais oun erchomenoi therapeuesthai, kai mē tē hēmera tou sabbatou.', 'The ruler (archisunagōgos — the administrator of the synagogue, a lay leader) addresses the crowd rather than Jesus directly — a sign of intimidation. "With indignation" (aganaktōn — burning with anger, greatly displeased). His logic is technically correct by Shammaite interpretation: healing could wait. But he addresses the crowd as if the woman should have waited — not addressing the healing itself but managing its social implications. His religion values a rule above an eighteen-year-old suffering.', NULL),
  (15, 'The Lord then answered him, and said, Thou hypocrite, doth not each one of you on the sabbath loose his ox or his ass from the stall, and lead him away to watering?', 'ἀπεκρίθη δὲ αὐτῷ ὁ Κύριος καὶ εἶπεν, Ὑποκριτά, ἕκαστος ὑμῶν τῷ σαββάτῳ οὐ λύει τὸν βοῦν αὐτοῦ ἢ τὸν ὄνον ἀπὸ τῆς φάτνης καὶ ἀπαγαγὼν ποτίζει;', 'apekrithē de autō ho Kurios kai eipen, Hupokrita, hekastos humōn tō sabbatō ou luei ton boun autou ē ton onon apo tēs phatnēs kai apagagōn potizei?', '"Thou hypocrite" (hupokrita — singular, addressed directly to the ruler) — a personal indictment. Jesus exposes the inconsistency: every Jew untied (luei — looses, the same root as "thou art loosed" in v.12) his working animals on the Sabbath to water them. No one challenged this necessary act of animal care. The rhetorical question expects "yes, of course." The man values livestock watering more than a daughter of Abraham''s healing.', NULL),
  (16, 'And ought not this woman, being a daughter of Abraham, whom Satan hath bound, lo, these eighteen years, be loosed from this bond on the sabbath day?', 'ταύτην δὲ θυγατέρα Ἀβραὰμ οὖσαν, ἣν ἔδησεν ὁ Σατανᾶς ἰδοὺ δεκαοκτὼ ἔτη, οὐκ ἔδει λυθῆναι ἀπὸ τοῦ δεσμοῦ τούτου τῇ ἡμέρᾳ τοῦ σαββάτου;', 'tautēn de thugatera Abraam ousan, hēn edēsen ho Satanas idou dekaOktō etē, ouk edei luthēnai apo tou desmou toutou tē hēmera tou sabbatou?', '"Daughter of Abraham" (thugatera Abraam) — she belongs to the covenant people; she has inheritance rights. "Whom Satan hath bound" (hēn edēsen ho Satanas — whom Satan has bound and the binding continues) — the perfect tense reveals the satanic character of her eighteen-year bondage. "Ought not" (ouk edei — was it not necessary, was it not fitting?) — the Sabbath, the day of liberation (Deut 15:15; Lev 25), is the most appropriate day to release a covenant daughter from satanic chains.', NULL),
  (17, 'And when he had said these things, all his adversaries were ashamed: and all the people rejoiced for all the glorious things that were done by him.', 'καὶ ταῦτα λέγοντος αὐτοῦ κατῃσχύνοντο πάντες οἱ ἀντικείμενοι αὐτῷ, καὶ πᾶς ὁ ὄχλος ἔχαιρεν ἐπὶ πᾶσιν τοῖς ἐνδόξοις τοῖς γινομένοις ὑπ'' αὐτοῦ.', 'kai tauta legontos autou katēschuNonto pantes hoi antikeimenoi autō, kai pas ho ochlos echiairen epi pasin tois endoxois tois ginomenois hyp'' autou.', '"Were ashamed" (katēschuNonto — put to shame, confounded) — the adversaries have no logical or theological response; they are reduced to silence and shame. The crowd''s reaction is the opposite: "rejoiced" (echiairen — was joyful, kept rejoicing) over "all the glorious things" (epi pasin tois endoxois — upon all the glorious, splendid, honorable things). The same event produces shame in the religious establishment and joy in the people — Luke''s characteristic contrast between leadership and populace.', NULL),
  (18, 'Then said he, Unto what is the kingdom of God like? and whereunto shall I resemble it?', 'Ἔλεγεν οὖν, Τίνι ὁμοία ἐστὶν ἡ βασιλεία τοῦ Θεοῦ, καὶ τίνι ὁμοιώσω αὐτήν;', 'Elegen oun, Tini homoia estin hē basileia tou Theou, kai tini homoiōsō autēn?', 'The twin parables of mustard seed and leaven are connected by "then" (oun — therefore, consequently) to the Sabbath healing: the liberation of the bent woman is itself a manifestation of the kingdom. The rhetorical double question ("unto what is it like? whereunto shall I compare it?") signals a particularly important teaching moment, inviting the audience to join in the imaginative act of comparison.', NULL),
  (19, 'It is like a grain of mustard seed, which a man took, and cast into his garden; and it grew, and waxed a great tree; and the fowls of the air lodged in the branches of it.', 'ὁμοία ἐστὶν κόκκῳ σινάπεως, ὃν λαβὼν ἄνθρωπος ἔβαλεν εἰς κῆπον ἑαυτοῦ· καὶ ηὔξησεν καὶ ἐγένετο εἰς δένδρον μέγα, καὶ τὰ πετεινὰ τοῦ οὐρανοῦ κατεσκήνωσεν ἐν τοῖς κλάδοις αὐτοῦ.', 'homoia estin kokkō sinapeōs, hon labōn anthrōpos ebalen eis kēpon heautou; kai ēuxēsen kai egeneto eis dendron mega, kai ta peteina tou ouranou kateskēnōsen en tois kladois autou.', 'The mustard seed (kokkō sinapeōs) was proverbially the smallest seed in Jewish usage. Yet it grows into a "great tree" (dendron mega) — hyperbole for the mustard''s actual shrub-like growth — in which birds nest (kateskēnōsen — roosted, made their nests), echoing Daniel 4:12 and Ezekiel 17:23 where the sheltering tree represents a great empire welcoming the nations. The birds represent Gentile nations finding shelter in the kingdom that began as a small Galilean movement.', NULL),
  (20, 'And again he said, Whereunto shall I liken the kingdom of God?', 'Καὶ πάλιν εἶπεν, Τίνι ὁμοιώσω τὴν βασιλείαν τοῦ Θεοῦ;', 'Kai palin eipen, Tini homoiōsō tēn basileian tou Theou?', 'The repeated question introduces the second parable in the pair. The doubling of the comparison (mustard seed + leaven) reflects the Hebrew poetic pattern of saying the same important thing twice with different images. Both parables address the same theme from different angles: external visible growth (mustard seed) and internal invisible permeation (leaven), together describing the kingdom''s comprehensive advance.', NULL),
  (21, 'It is like leaven, which a woman took and hid in three measures of meal, till the whole was leavened.', 'ὁμοία ἐστὶν ζύμῃ, ἣν λαβοῦσα γυνὴ ἔκρυψεν εἰς ἀλεύρου σάτα τρία, ἕως οὗ ἐζυμώθη ὅλον.', 'homoia estin zumē, hēn labousa gunē ekrupsen eis aleurou sata tria, heōs hou ezumōthē holon.', 'Leaven (zumē) was normally a symbol of corruption (12:1); here its pervasive, transformative power illustrates the kingdom''s inward work. "Three measures" (sata tria — about 50 pounds of flour, enough for bread for 100+ people) is an enormous amount — a festive or communal baking. The leaven is "hidden" (ekrupsen — concealed within) and works invisibly until the whole is leavened. The kingdom transforms societies from within, not only by visible proclamation but by hidden, pervasive influence.', NULL),
  (22, 'And he went through the cities and villages, teaching, and journeying toward Jerusalem.', 'Καὶ διεπορεύετο κατὰ πόλεις καὶ κώμας διδάσκων καὶ πορείαν ποιούμενος εἰς Ἱεροσόλυμα.', 'Kai dieporeueto kata poleis kai kōmas didaskōn kai poreian poioumenos eis Hierosoluma.', 'A travel notice that reminds the reader that the entire section from 9:51 takes place on the journey to Jerusalem. "Journeying toward Jerusalem" (poreian poioumenos eis Hierosoluma — making a journey toward Jerusalem) — the capital and the cross are never far from view. The cities and villages represent the comprehensive scope of Jesus''s teaching mission even as he moves toward his appointed end. The question that follows arises from the atmosphere of this journey.', NULL),
  (23, 'Then said one unto him, Lord, are there few that be saved? And he said unto them,', 'εἶπεν δέ τις αὐτῷ, Κύριε, εἰ ὀλίγοι οἱ σῳζόμενοι; ὁ δὲ εἶπεν πρὸς αὐτούς,', 'eipen de tis autō, Kurie, ei oligoi hoi sōzomenoi; ho de eipen pros autous,', 'The question "are there few that be saved?" (ei oligoi hoi sōzomenoi — whether few are those being saved?) is a theological discussion question common in rabbinic circles (b. Sanh. 97b-98a debated whether most or few would be saved). The person expects Jesus to arbitrate the debate. Jesus refuses to answer the speculative question and redirects to personal urgency — "strive to enter." He addresses the crowd ("unto them") not the individual, expanding the application.', NULL),
  (24, 'Strive to enter in at the strait gate: for many, I say unto you, will seek to enter in, and shall not be able.', 'Ἀγωνίζεσθε εἰσελθεῖν διὰ τῆς στενῆς θύρας· ὅτι πολλοί, λέγω ὑμῖν, ζητήσουσιν εἰσελθεῖν καὶ οὐκ ἰσχύσουσιν.', 'Agōnizesthe eiselthein dia tēs stenēs thuras; hoti polloi, legō humin, zētēsousin eiselthein kai ouk ischuRousin.', '"Strive" (agōnizesthe — agonize, compete in an athletic contest, give maximum effort) — the entrance to salvation requires determined, active engagement, not casual assumption. "The strait gate" (tēs stenēs thuras — the narrow door) suggests that the entrance is limited in width: it accommodates one at a time, by personal decision. "Many will seek to enter and shall not be able" — not because the door is locked to them but because they seek at the wrong time or by the wrong means.', NULL),
  (25, 'When once the master of the house is risen up, and hath shut to the door, and ye begin to stand without, and to knock at the door, saying, Lord, Lord, open unto us; and he shall answer and say unto you, I know you not whence ye are:', 'ἀφ'' οὗ ἂν ἐγερθῇ ὁ οἰκοδεσπότης καὶ ἀποκλείσῃ τὴν θύρον, καὶ ἄρξησθε ἔξω ἑστάναι καὶ κρούειν τὴν θύρον λέγοντες, Κύριε, ἄνοιξον ἡμῖν· καὶ ἀποκριθεὶς ἐρεῖ ὑμῖν, Οὐκ οἶδα ὑμᾶς πόθεν ἐστέ.', 'aph'' hou an egerthē ho oikodespotēs kai apokleisē tēn thuron, kai arxēsthe exō hestanai kai krouein tēn thuron legontes, Kurie, anoixon hēmin; kai apokritheis erei humin, Ouk oida humas pothen este.', 'The imagery shifts to a closed door and a master who has risen and shut it (apokleisē — locked, shut tight). "I know you not whence ye are" (ouk oida humas pothen este — I do not know you or where you come from) — a formal statement of non-recognition. The door was open during the time of Jesus''s ministry; his death and resurrection would close the era of grace. Those who intended to enter "later" discover that later has become too late.', NULL),
  (26, 'Then shall ye begin to say, We have eaten and drunk in thy presence, and thou hast taught in our streets.', 'τότε ἄρξεσθε λέγειν, Ἐφάγομεν ἐνώπιόν σου καὶ ἐπίομεν, καὶ ἐν ταῖς πλατείαις ἡμῶν ἐδίδαξας·', 'tote arxesthe legein, Ephagomen enōpion sou kai epiomen, kai en tais plateiais hēmōn edidaxas;', 'The excluded appeal to proximity — "we ate and drank in your presence, you taught in our streets." Physical proximity to Jesus, attending his meals, living in towns where he preached — none of these constitute the personal relationship that the narrow gate requires. The claim is geographic and cultural, not relational and transformative. This is the claim of nominal religion: being nearby without being within, hearing without obeying.', NULL),
  (27, 'But he shall say, I tell you, I know you not whence ye are; depart from me, all ye workers of iniquity.', 'καὶ ἐρεῖ λέγων ὑμῖν, Οὐκ οἶδα πόθεν ἐστέ· ἀπόστητε ἀπ'' ἐμοῦ, πάντες ἐργάται ἀδικίας.', 'kai erei legōn humin, Ouk oida pothen este; apostēte ap'' emou, pantes ergatai adikias.', '"Depart from me" (apostēte ap'' emou — stand away from me, withdraw) echoes Psalm 6:8, which Jesus quotes (Matt 7:23 uses the same Psalm). "Workers of iniquity" (ergatai adikias — those who work unrighteousness, practitioners of injustice) — the excluded are not passive bystanders but active practitioners of wrong. Despite proximity to Jesus, their fundamental orientation was toward sin. The repetition of "I know you not whence ye are" is the double judgment, sealed with a command to depart.', NULL),
  (28, 'There shall be weeping and gnashing of teeth, when ye shall see Abraham, and Isaac, and Jacob, and all the prophets, in the kingdom of God, and you yourselves thrust out.', 'ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων, ὅταν ὄψησθε Ἀβραὰμ καὶ Ἰσαὰκ καὶ Ἰακὼβ καὶ πάντας τοὺς προφήτας ἐν τῇ βασιλείᾳ τοῦ Θεοῦ, ὑμᾶς δὲ ἐκβαλλομένους ἔξω.', 'ekei estai ho klauthmos kai ho brugmos tōn odontōn, hotan opsēsthe Abraam kai Isaak kai Iakōb kai pantas tous prophētas en tē basileia tou Theou, humas de ekballomenous exō.', '"Weeping and gnashing of teeth" (klauthmos kai brugmos tōn odontōn) — the combination of grief (weeping) and rage (gnashing) describes the specific torment of exclusion when one sees what might have been. "Ye shall see" (opsēsthe) — they will have clear vision of Abraham, Isaac, Jacob, and all the prophets in the kingdom — their own patriarchal heritage — while being "thrust out" (ekballomenous exō — continuously being cast outside). The sight of what is lost intensifies the anguish.', NULL),
  (29, 'And they shall come from the east, and from the west, and from the north, and from the south, and shall sit down in the kingdom of God.', 'καὶ ἥξουσιν ἀπὸ ἀνατολῶν καὶ δυσμῶν καὶ ἀπὸ βορρᾶ καὶ νότου καὶ ἀνακλιθήσονται ἐν τῇ βασιλείᾳ τοῦ Θεοῦ.', 'kai hēxousin apo anatolōn kai dusmōn kai apo borra kai notou kai anakiithēsontai en tē basileia tou Theou.', 'From all four compass points — a comprehensive universalism echoing Isaiah 43:5-6; 49:12; Psalm 107:3. "Shall sit down" (anakIithēsontai — will recline at table) — the great eschatological banquet (Isa 25:6). Gentiles from every direction will recline as honored guests at the messianic feast, while those who assumed ancestral right discover they are outside. The reversal is complete: the geographical outsiders become the insiders; the ethnic insiders become the outcasts.', NULL),
  (30, 'And, behold, there are last which shall be first, and there are first which shall be last.', 'καὶ ἰδοὺ εἰσὶν ἔσχατοι οἳ ἔσονται πρῶτοι, καὶ εἰσὶν πρῶτοι οἳ ἔσονται ἔσχατοι.', 'kai idou eisin eschatoi hoi esontai prōtoi, kai eisin prōtoi hoi esontai eschatoi.', '"Behold" (idou) signals a surprising, important statement. The reversal of first and last is one of Jesus''s most repeated paradoxes (14:11; 18:14; Matt 19:30; 20:16; Mark 10:31), expressed here in its eschatological form. "Last" (eschatoi) refers to those currently marginalized — Gentiles, sinners — who will be first in the kingdom. "First" (prōtoi) refers to those who consider themselves at the front of the queue — religious insiders — who will be last. Eschatological priority is determined by response to grace, not ethnic or religious position.', NULL),
  (31, 'The same day there came certain of the Pharisees, saying unto him, Get thee out, and depart hence: for Herod will kill thee.', 'Ἐν αὐτῇ τῇ ἡμέρᾳ προσῆλθάν τινες Φαρισαῖοι λέγοντες αὐτῷ, Ἔξελθε καὶ πορεύου ἐντεῦθεν, ὅτι Ἡρῴδης θέλει σε ἀποκτεῖναι.', 'En autē tē hēmera prosēlthon tines Pharisaioi legontes autō, Exelthe kai poreuou enteuthen, hoti Hērōdēs thelei se apokteinai.', 'Uniquely, Pharisees warn Jesus about Herod''s threat — an unusual scene suggesting either genuine concern or a political maneuver to frighten Jesus away from his mission. Herod Antipas (who killed John the Baptist, 3:19-20) was tetrarch of Galilee and Perea. "Get thee out" (Exelthe kai poreuou — go out and depart from here) — whether friendly warning or veiled threat, the message is the same: leave. Jesus''s response refuses to be hurried.', NULL),
  (32, 'And he said unto them, Go ye, and tell that fox, Behold, I cast out devils, and I do cures to day and to morrow, and the third day I shall be perfected.', 'καὶ εἶπεν αὐτοῖς, Πορευθέντες εἴπατε τῇ ἀλώπεκι ταύτῃ, Ἰδοὺ ἐκβάλλω δαιμόνια καὶ ἰάσεις ἀποτελῶ σήμερον καὶ αὔριον, καὶ τῇ τρίτῃ τελειοῦμαι.', 'kai eipen autois, Poreuthentes eipate tē alōpeki tautē, Idou ekballō daimonia kai iaseis apotelō sēmeron kai aurion, kai tē tritē telEioumai.', '"That fox" (tē alōpeki tautē — that fox) — in Jewish tradition, a fox was a cunning but weak animal compared to a lion. Jesus dismisses Herod as a petty schemer rather than a genuine threat to his mission. "Today and tomorrow" symbolize the continuing ministry; "the third day I shall be perfected" (telEioumai — completed, accomplished, brought to full completion) points to the cross and resurrection as the fulfillment of his redemptive purpose, not a death imposed by Herod.', NULL),
  (33, 'Nevertheless I must walk to day, and to morrow, and the day following: for it cannot be that a prophet perish out of Jerusalem.', 'πλὴν δεῖ με σήμερον καὶ αὔριον καὶ τῇ ἐχομένῃ πορεύεσθαι· ὅτι οὐκ ἐνδέχεται προφήτην ἀπολέσθαι ἔξω Ἱερουσαλήμ.', 'plēn dei me sēmeron kai aurion kai tē echomenē poreuesthai; hoti ouk endechetai prophētēn apolEsthai exō Hierousalēm.', '"I must" (dei me — it is necessary for me) — the divine necessity that governs Jesus''s entire journey. Herod cannot terminate his mission because the appointed place of a prophet''s death is Jerusalem (see v.34). The bitter irony is sharp: the holy city, the city of God''s chosen dwelling, is the city that kills prophets. Jerusalem does not protect its prophets — it destroys them. Jesus will not be deflected from his destiny by a Galilean tetrarch.', NULL),
  (34, 'O Jerusalem, Jerusalem, which killest the prophets, and stonest them that are sent unto thee; how often would I have gathered thy children together, as a hen doth gather her brood under her wings, and ye would not!', 'Ἰερουσαλήμ, Ἰερουσαλήμ, ἡ ἀποκτείνουσα τοὺς προφήτας καὶ λιθοβολοῦσα τοὺς ἀπεσταλμένους πρὸς αὐτήν· ποσάκις ἠθέλησα ἐπισυνάξαι τὰ τέκνα σου ὃν τρόπον ὄρνις τὴν ἑαυτῆς νοσσιὰν ὑπὸ τὰς πτέρυγας, καὶ οὐκ ἠθελήσατε.', 'Hierousalēm, Hierousalēm, hē apokteInousa tous prophētas kai lithobolousa tous apestalmenous pros autēn; posakis ēthelēsa episunaxai ta tekna sou hon tropon ornis tēn heautēs nossian hupo tas pterugas, kai ouk ēthelēsate.', 'The double address "Jerusalem, Jerusalem" is a classic lament form (cf. "Absalom, Absalom!" 2 Sam 19:4; "Martha, Martha" 10:41). The hen-and-chicks image (ornis — a female bird, perhaps a hen) is one of the most tender Christological images in the Gospels: the divine longing to shelter, protect, and gather. "How often I would" (posakis ēthelēsa — how many times I desired, with personal longing) — the repeated divine initiative met by "ye would not" (ouk ēthelēsate — you did not will it, you refused). The tragedy of rejected grace.', NULL),
  (35, 'Behold, your house is left unto you desolate: and verily I say unto you, Ye shall not see me, until the time come when ye shall say, Blessed is he that cometh in the name of the Lord.', 'ἰδοὺ ἀφίεται ὑμῖν ὁ οἶκος ὑμῶν. λέγω δὲ ὑμῖν, οὐ μὴ ἴδητέ με ἕως ἥξει ὅτε εἴπητε, Εὐλογημένος ὁ ἐρχόμενος ἐν ὀνόματι Κυρίου.', 'idou aphietai humin ho oikos humōn. legō de humin, ou mē idēte me heōs hēxei hote eipēte, Eulogēmenos ho erchomenos en onomati Kuriou.', '"Your house is left unto you desolate" (aphietai — is abandoned, given up, forsaken) — "your house" not "my Father''s house." The divine presence is withdrawing from the temple and the city that has rejected its prophets. This prophecy anticipates the destruction of Jerusalem in AD 70 (21:5-24). "Ye shall not see me until" — not permanent absence but conditional future restoration: when they cry "Blessed is he that cometh" (Ps 118:26), quoting the Passover hallel, the reunion will occur — at the triumphal entry (19:38) and ultimately at the parousia.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 13;
